const listing = $input.first().json;
const flairName = ($env.AI_DETECTOR_MEGATHREAD_FLAIR || 'New Project Megathread').toLowerCase();
const posts = (listing?.data?.children ?? []).map((child) => child.data).filter(Boolean);
const monthIndexes = new Map(Object.entries({ jan: 0, january: 0, feb: 1, february: 1, mar: 2, march: 2, apr: 3, april: 3, may: 4, jun: 5, june: 5, jul: 6, july: 6, aug: 7, august: 7, sep: 8, sept: 8, september: 8, oct: 9, october: 9, nov: 10, november: 10, dec: 11, december: 11 }));
function parseWeekDate(title) {
  const match = String(title || '').match(/week\s+of\s+(\d{1,2})\s+([a-z]{3,9})\s+(\d{4})/i);
  if (!match) return null;
  const monthIndex = monthIndexes.get(match[2].toLowerCase());
  if (monthIndex === undefined) return null;
  return new Date(Date.UTC(Number(match[3]), monthIndex, Number(match[1])));
}
const now = new Date();
const oneDayMs = 24 * 60 * 60 * 1000;
const currentWindowMs = 8 * oneDayMs;
const flairMatches = posts.filter((post) => String(post.link_flair_text || '').toLowerCase() === flairName);
const datedMatches = flairMatches.map((post) => ({ post, weekDate: parseWeekDate(post.title) })).filter(({ weekDate }) => weekDate && weekDate.getTime() <= now.getTime() + oneDayMs && now.getTime() - weekDate.getTime() < currentWindowMs).sort((a, b) => b.weekDate.getTime() - a.weekDate.getTime());
const selected = datedMatches[0]?.post ?? flairMatches.sort((a, b) => Number(b.created_utc || 0) - Number(a.created_utc || 0))[0];
if (!selected) {
  return [];
}
return [{
  json: {
    thread_id: selected.id,
    thread_fullname: selected.name,
    thread_title: selected.title,
    thread_flair: selected.link_flair_text,
    thread_permalink: `https://www.reddit.com${selected.permalink}`,
    comments_url: `https://www.reddit.com/comments/${selected.id}.json?limit=500&sort=new`
  }
}];

const response = $input.first().json;
const staticData = $getWorkflowStaticData('global');
staticData.processedCommentIds = staticData.processedCommentIds || {};
const seen = staticData.processedCommentIds;
const thread = Array.isArray(response) ? response[0]?.data?.children?.[0]?.data : undefined;
const comments = Array.isArray(response) ? response[1]?.data?.children ?? [] : [];
const threadFullname = thread?.name;
const repoPattern = /https?:\/\/(?:www\.)?(?:github\.com|gitlab\.com|codeberg\.org)\/[A-Za-z0-9_.-]+\/[A-Za-z0-9_.-]+(?:\.git)?(?:[/?#][^\s)\]}>'"]*)?|https?:\/\/git\.sr\.ht\/[~A-Za-z0-9_.-]+\/[A-Za-z0-9_.-]+(?:\.git)?(?:[/?#][^\s)\]}>'"]*)?/gi;
const output = [];
for (const child of comments) {
  if (child.kind !== 't1') continue;
  const comment = child.data;
  if (!comment || comment.parent_id !== threadFullname) continue;
  if (seen[comment.id]) continue;
  const body = comment.body || '';
  const repoUrls = [...new Set((body.match(repoPattern) || []).map((url) => url.replace(/[.,;:]+$/, '')))];
  if (repoUrls.length === 0) continue;
  seen[comment.id] = new Date().toISOString();
  for (const repoUrl of repoUrls) {
    output.push({
      json: {
        repo_url: repoUrl,
        comment_id: comment.id,
        comment_permalink: `https://www.reddit.com${comment.permalink}`,
        author: comment.author,
        thread_id: thread?.id,
        thread_title: thread?.title
      }
    });
  }
}
return output;
